  import java.io.FileInputStream;
  import java.io.FileNotFoundException;
  import java.io.IOException;
  import java.util.ArrayList;
  import java.util.HashMap;
  import java.util.List;
  import java.util.Map;
  import java.util.Scanner;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  import sailpoint.api.ObjectUtil;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Identity;
  import sailpoint.object.TaskResult;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Message;
  import sailpoint.tools.Util;




  public  List delimToList(String delimiter,String lineString){
    List result = new ArrayList();
    if(Util.isNotNullOrEmpty(lineString)){
      if(Util.isNotNullOrEmpty(delimiter) && delimiter.equals(",")){
        List <String>tempList = Util.csvToList(lineString);
        for(String str : tempList){
          if(Util.isNullOrEmpty(str)){
            str = "";
          }
          result.add(str.trim());
        }
      }else{
        String []str = lineString.split(delimiter);
        for(String s : str){
          if(Util.isNullOrEmpty(s)){
            s = "";
          }
          result.add(s.trim());
        }
      }
    }
    return result;
  }

  public String nextInitialName(){
    String result = "";
    result = prefix + String.format("%08d", initialCounter++);
    return result;
  }


  public  void createIdentity(Map identityMap) throws GeneralException{

   

    Identity peopleCube = null;
    Identity morriseyCube = null;
    Identity mdstaffCube = null;
    Identity avatarCube = null;
    boolean isNewIdentity = false;
    String parentPersonaSID = "";
    String parentPersonaName = "";
    List childPersonaNames = new ArrayList();
    List childPersonas = new ArrayList();
    String initialName = "";
    String internalId = "";


    processLog = "\n";
    boolean isPrimaryIdentityExist = false;
    Identity tempIdentity = null;

    try{
      if(!Util.isEmpty(identityMap)){
        // identify which primary identity exists
        if(Util.isNotNullOrEmpty(identityMap.get(primary_sAMAccountName))){
          tempIdentity = context.getObjectByName(Identity.class, identityMap.get(primary_sAMAccountName));
          if(tempIdentity!=null){
            isPrimaryIdentityExist =  true;
            //comment decache //context.decache(tempIdentity);
          }
        }


        // Process Peoplesoft
        if(Util.isNotNullOrEmpty(identityMap.get(symphony_id))){

          peopleCube = context.getObjectByName(Identity.class, identityMap.get(symphony_id));

          // people soft identity not found ,create new one
          if(peopleCube == null){
            peopleCube = new Identity();
            isNewIdentity = true;
            peopleCube.setName(identityMap.get(symphony_id));
            peopleCube.setFirstname(identityMap.get(firstname));
            peopleCube.setLastname(identityMap.get(lastname));
            peopleCube.setManager(managerIdentity);
            

            if(Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_peoplesoft)){
              peopleCube.setAttribute("samAccountName", identityMap.get(primary_sAMAccountName));
            }
          }else{
            
          }

          // set default att
          internalId = "";
          initialName = "";
          internalId = generateNextSailpointInternalIdentifier();
          initialName =  nextInitialName();
          

          peopleCube.setAttribute("identityType", "EmployeePersona");
          peopleCube.setAttribute("initialName", initialName);
          peopleCube.setAttribute("internalId", internalId);
		  
		  peopleCube.setAttribute("courionId", identityMap.get(profileuid));



          // set when peoplesoft is primary source
          if(Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_peoplesoft)){
            peopleCube.setAttribute("personaType", "Primary");
            parentPersonaSID = internalId;
            parentPersonaName = peopleCube.getName();
            processLog = processLog + identityMap.get(profileuid)+ "|" + "PeopleSoft"+ "|" +"Primary" + "|" + peopleCube.getName() + "|" + internalId +"\n";
          }else{
            peopleCube.setAttribute("personaType", "Child");
            childPersonaNames.add(peopleCube.getName());
            childPersonas.add(internalId);
            processLog = processLog + identityMap.get(profileuid)+ "|" + "PeopleSoft"+ "|" +"Child" + "|" + peopleCube.getName() + "|" + internalId +"\n";
          }

			//set protected to prevent deletion
			peopleCube.setProtected(true);
						

          context.saveObject(peopleCube);
          if(!isNewIdentity){
            
          }

        }


        // Process Morrisey  //
        if(Util.isNotNullOrEmpty(identityMap.get(morrisey_id))){

          isNewIdentity = false;
          internalId = "";
          initialName = "";

          internalId = generateNextSailpointInternalIdentifier();
          initialName =  nextInitialName();
          

          // morrisey identity not found ,create new one
          if(!isPrimaryIdentityExist || !Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_morrisey)){
            morriseyCube = new Identity();
            isNewIdentity = true;
            morriseyCube.setFirstname(identityMap.get(firstname));
            morriseyCube.setLastname(identityMap.get(lastname));

            morriseyCube.setName(initialName);
            morriseyCube.setManager(managerIdentity);
            
          }else{
            
            morriseyCube = context.getObjectByName(Identity.class, identityMap.get(primary_sAMAccountName));
          }					

          // set default att
          morriseyCube.setAttribute("identityType", "ProviderPersona");
          morriseyCube.setAttribute("initialName", initialName);
          morriseyCube.setAttribute("internalId", internalId);
          morriseyCube.setAttribute("providerID", identityMap.get(morrisey_id));
		  
		  morriseyCube.setAttribute("courionId", identityMap.get(profileuid));



          // set when morrisey is primary source
          if(Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_morrisey)){
            if(Util.isNotNullOrEmpty(identityMap.get(primary_sAMAccountName))){
              morriseyCube.setName(identityMap.get(primary_sAMAccountName)); 
            }
            morriseyCube.setAttribute("personaType", "Primary");
            parentPersonaSID = internalId;
            parentPersonaName = morriseyCube.getName();
            morriseyCube.setAttribute("samAccountName", identityMap.get(primary_sAMAccountName));
            processLog = processLog + identityMap.get(profileuid)+ "|" + "Morrisey"+ "|" +"Primary" + "|" + morriseyCube.getName() + "|" + internalId +"\n";
          }else{
            morriseyCube.setAttribute("personaType", "Child");
            childPersonaNames.add(morriseyCube.getName());
            childPersonas.add(internalId);
            processLog = processLog + identityMap.get(profileuid)+ "|" + "Morrisey"+ "|" +"Child" + "|" + morriseyCube.getName() + "|" + internalId +"\n";
          }
		  
			//set protected to prevent deletion
			morriseyCube.setProtected(true);
			

          context.saveObject(morriseyCube);
          if(!isNewIdentity){
            
          }

        }


        // Process MDStaff
        if(Util.isNotNullOrEmpty(identityMap.get(MDSTAFF_ID))){

          isNewIdentity = false;
          internalId = "";
          initialName = "";
          internalId = generateNextSailpointInternalIdentifier();
          initialName =  nextInitialName();
          

          // mdstaff identity not found ,create new one
          if(!isPrimaryIdentityExist || !Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_mdstaff)){
            mdstaffCube = new Identity();
            isNewIdentity = true;
            mdstaffCube.setFirstname(identityMap.get(firstname));
            mdstaffCube.setLastname(identityMap.get(lastname));

            mdstaffCube.setName(initialName);
            mdstaffCube.setManager(managerIdentity);

            
          }else{
            
            mdstaffCube = context.getObjectByName(Identity.class, identityMap.get(primary_sAMAccountName));
          }	

          // set default att
          mdstaffCube.setAttribute("identityType", "ProviderPersona");
          mdstaffCube.setAttribute("initialName", initialName);
          mdstaffCube.setAttribute("internalId", internalId);
          mdstaffCube.setAttribute("providerID", identityMap.get(MDSTAFF_ID));
		  
		  mdstaffCube.setAttribute("courionId", identityMap.get(profileuid));



          // set when mdstaff is primary source
          if(Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_mdstaff)){
            if(Util.isNotNullOrEmpty(identityMap.get(primary_sAMAccountName))){
              mdstaffCube.setName(identityMap.get(primary_sAMAccountName)); // create identity and set samaccountname and identityname
            }
            mdstaffCube.setAttribute("personaType", "Primary");
            parentPersonaSID = internalId;
            parentPersonaName = mdstaffCube.getName();
            mdstaffCube.setAttribute("samAccountName", identityMap.get(primary_sAMAccountName));
            processLog = processLog + identityMap.get(profileuid)+ "|" + "MDStaff"+ "|" +"Primary" + "|" + mdstaffCube.getName() + "|" + internalId +"\n";
          }else{
            mdstaffCube.setAttribute("personaType", "Child");
            childPersonaNames.add(mdstaffCube.getName());
            childPersonas.add(internalId);
            processLog = processLog + identityMap.get(profileuid)+ "|" + "MDStaff"+ "|" +"Child" + "|" + mdstaffCube.getName() + "|" + internalId +"\n";
          }

			//set protected to prevent deletion
			mdstaffCube.setProtected(true);
			
          context.saveObject(mdstaffCube);
          if(!isNewIdentity){
            
          }

        }

        // Process Avatar
        if(Util.isNotNullOrEmpty(identityMap.get(avatar_id))){

          isNewIdentity = false;
          internalId = "";
          initialName = "";
          internalId = generateNextSailpointInternalIdentifier();
          initialName =  nextInitialName();
          

          // avatar identity not found ,create new one
          if(!isPrimaryIdentityExist || !Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_avatar)){
            avatarCube = new Identity();
            isNewIdentity = true;
            avatarCube.setFirstname(identityMap.get(firstname));
            avatarCube.setLastname(identityMap.get(lastname));

            avatarCube.setName(initialName); 
            avatarCube.setManager(managerIdentity);

            
          }else{
            
            avatarCube = context.getObjectByName(Identity.class, identityMap.get(primary_sAMAccountName));
          }					
          // set default att
          avatarCube.setAttribute("type", "non-hr contractor");
          avatarCube.setAttribute("identityType", "NonHRContractorPersona");
          avatarCube.setAttribute("initialName", initialName);
          avatarCube.setAttribute("internalId", internalId);
		  
		  avatarCube.setAttribute("domain", "AMITA");
          avatarCube.setAttribute("ministry", "AMITA Health");
		  
		  avatarCube.setAttribute("courionId", identityMap.get(profileuid));

          // store avatar id in iiq att avatarId
          avatarCube.setAttribute("avatarId", identityMap.get(avatar_id));


          // set when mdstaff is primary source
          if(Util.nullSafeCaseInsensitiveEq(identityMap.get(primary_authsource), auth_avatar)){
            if(Util.isNotNullOrEmpty(identityMap.get(primary_sAMAccountName))){
              avatarCube.setName(identityMap.get(primary_sAMAccountName)); 	
            }
            avatarCube.setAttribute("personaType", "Primary");
            parentPersonaSID = internalId;
            parentPersonaName = avatarCube.getName();
            avatarCube.setAttribute("samAccountName", identityMap.get(primary_sAMAccountName));

            processLog = processLog + identityMap.get(profileuid)+ "|" + "Avatar"+ "|" +"Primary" + "|" + avatarCube.getName() + "|" + internalId +"\n";
          }else{

            avatarCube.setAttribute("personaType", "Child");
            childPersonaNames.add(avatarCube.getName());
            childPersonas.add(internalId);
            processLog = processLog + identityMap.get(profileuid)+ "|" + "Avatar"+ "|" +"Child" + "|" + avatarCube.getName() + "|" + internalId +"\n";
          }
			//set protected to prevent deletion
			avatarCube.setProtected(true);
			
          context.saveObject(avatarCube);
          if(!isNewIdentity){
            
          }

        }


        // establish Parent child relationship  
        if(peopleCube!=null){

          if(Util.nullSafeCaseInsensitiveEq(peopleCube.getStringAttribute("personaType") ,"Child") ){
            peopleCube.setAttribute("parentPersonaName", parentPersonaName);
            peopleCube.setAttribute("parentPersonaSID", parentPersonaSID);
          }else{
            peopleCube.setAttribute("childPersonaNames", childPersonaNames);
            peopleCube.setAttribute("childPersonas", childPersonas);
          }
		  	
          context.saveObject(peopleCube);
          peoplesoftCount++;
        }

        if(morriseyCube!=null){



          if(Util.nullSafeCaseInsensitiveEq(morriseyCube.getStringAttribute("personaType") ,"Child") ){
            morriseyCube.setAttribute("parentPersonaName", parentPersonaName);
            morriseyCube.setAttribute("parentPersonaSID", parentPersonaSID);
          }else{
            morriseyCube.setAttribute("childPersonaNames", childPersonaNames);
            morriseyCube.setAttribute("childPersonas", childPersonas);
          }
			
          context.saveObject(morriseyCube);
          morriseyCount++;
        }

        if(mdstaffCube!=null){

          if(Util.nullSafeCaseInsensitiveEq(mdstaffCube.getStringAttribute("personaType") ,"Child") ){
            mdstaffCube.setAttribute("parentPersonaName", parentPersonaName);
            mdstaffCube.setAttribute("parentPersonaSID", parentPersonaSID);
          }else{
            mdstaffCube.setAttribute("childPersonaNames", childPersonaNames);
            mdstaffCube.setAttribute("childPersonas", childPersonas);
          }
			
          context.saveObject(mdstaffCube);
          mdstaffCount++;
        }

        if(avatarCube!=null){

          if(Util.nullSafeCaseInsensitiveEq(avatarCube.getStringAttribute("personaType") ,"Child") ){
            avatarCube.setAttribute("parentPersonaName", parentPersonaName);
            avatarCube.setAttribute("parentPersonaSID", parentPersonaSID);
          }else{
            avatarCube.setAttribute("childPersonaNames", childPersonaNames);
            avatarCube.setAttribute("childPersonas", childPersonas);
          }
		  	
          context.saveObject(avatarCube);
          avatarCount++;
        }


        if(initialCounter%1000==0){
          context.commitTransaction();
        }
      }
    }catch(Exception ex){
      logger.error("Exception in create Identity "+ex.getMessage());
      taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+ex.getMessage(), null));

    }finally{
      //write to log

      logToFile(processLog,logFile);
    }

  }




  public void readData() throws Exception {

    String DELIMITER = ",";
    String inputFileName = "";
    boolean isHeader = true;
    String lineString ="";
    FileInputStream inputFile = null;
    Scanner scanner = null;
    List <String>headerList = new ArrayList();
    List dataList = new ArrayList();

    String counterStr = "";

    try {
      if(config!=null){
        try{
          inputFileName =  config.get("filePath").trim();
          managerName =    config.get("managerName").trim();
          logFile = 		 config.get("logFile").trim();
          prefix = 		 config.get("prefix").trim();
          counterStr = 	 config.get("initialCounter").trim();
        }catch(Exception ex){
          throw new  GeneralException("Invalid Inputs. Enter valid input.");
        }
      }


      if(Util.isNullOrEmpty(prefix)){
        throw new  GeneralException("Prefix is blank. Enter char eg.[A,AA,ZZZ]");
      }

      if(Util.isNullOrEmpty(counterStr)){
        throw new  GeneralException("Initial counter is blank. Enter Integer Value.");
      }else{
        try{
          initialCounter = Integer.parseInt(counterStr);
        }catch(Exception ex){
          throw new  GeneralException("Invalid Input Initial counter. Enter Integer Value.");
        }
      }

      managerIdentity = context.getObjectByName(Identity.class, managerName);
      if(managerIdentity == null){

        throw new  GeneralException("Manager not found. Check input.");
      }

      logToFile("profileuid|Application|Type|UserName|internalId",logFile);

      inputFile = new FileInputStream(inputFileName); 

      scanner = new Scanner(inputFile); 

      while (scanner!=null && scanner.hasNextLine()) {
        lineString = scanner.nextLine();


        if(Util.isNotNullOrEmpty(lineString)){
          if(isHeader){
            isHeader = false;
            headerList = delimToList(DELIMITER , lineString);
            continue;
          }
          inputRecordCounter++;
          feedMap = null;
          feedMap = new HashMap();
          counter = 0;
          for( String col : headerList){
            dataList = delimToList(DELIMITER , lineString);
            if(dataList!=null && dataList.size() == headerList.size()){
              if(Util.nullSafeCaseInsensitiveEq(dataList.get(counter), "null") ||  Util.isNullOrEmpty(dataList.get(counter)) ){
                feedMap.put(col, "");
              }else{
                feedMap.put(col, dataList.get(counter));
              }
            }
            counter++;
          }

          if(!Util.isEmpty(feedMap)){

            createIdentity(feedMap); 

          }
        }
      }// while end
      context.commitTransaction();
    }catch (FileNotFoundException e) {
      logger.error("Exception in update user "+e.getMessage());
      taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));

    }catch (GeneralException e) {
      logger.error("Exception in update user "+e.getMessage());
      taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));

    }finally{
      if(scanner!=null){
        scanner.close();
      }
      if(inputFile!=null){
        try {
          inputFile.close();
        } catch (IOException e) {
          logger.error("Exception in "+e.getMessage());
          taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
        }
      }
    }

  }

  /* Rule start from below */
  Log logger = LogFactory.getLog("Ascension-Rule-Migration-Load-Courion");
  logger.debug("Ascension-Rule-Migration-Load-Courion Start");

  int initialCounter = 1;
  String prefix = ""; 

  String processLog = "\n";
  String logFile = "";

  String auth_peoplesoft = "Symphony";
  String auth_morrisey = "Morrisey";
  String auth_avatar = "Avatar";
  String auth_mdstaff = "MDStaff";

  String profileuid = "profileuid";
  String firstname = "firstname";
  String lastname = "lastname";
  String symphony_id = "symphony_id";
  String morrisey_id = "morrisey_id";
  String MDSTAFF_ID = "MDSTAFF_ID";
  String avatar_id = "avatar_id";
  String primary_sAMAccountName = "primary_sAMAccountName";
  String primary_authsource = "primary_authsource";
  int counter = 0;
  Map feedMap =null;
  int inputRecordCounter = 0 ;
  String managerName = "";
  Identity managerIdentity ;

  int morriseyCount = 0;
  int mdstaffCount = 0;
  int peoplesoftCount = 0;
  int avatarCount = 0;


  readData();


  taskResult.setAttribute("morriseyCount",morriseyCount);  
  taskResult.setAttribute("mdstaffCount",mdstaffCount);  
  taskResult.setAttribute("peoplesoftCount",peoplesoftCount);  
  taskResult.setAttribute("avatarCount",avatarCount);  
  taskResult.setAttribute("inputRecordCounter",inputRecordCounter); 


  logger.debug("Ascension-Rule-Migration-Load-Courion End");

  return ""+inputRecordCounter;
